"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[203],{5487:n=>{n.exports=JSON.parse('{"blogPosts":[{"id":"locol","metadata":{"permalink":"/UIF_help/blog/locol","editUrl":"https://github.com/UIforFreedom/UIF/doc/blog/blog/2024-04-20-locol/index.md","source":"@site/blog/2024-04-20-locol/index.md","title":"\u5185\u7f51\u7a7f\u900f","description":"---","date":"2024-04-20T00:00:00.000Z","formattedDate":"April 20, 2024","tags":[{"label":"\u5185\u7f51\u7a7f\u900f","permalink":"/UIF_help/blog/tags/\u5185\u7f51\u7a7f\u900f"},{"label":"VPS","permalink":"/UIF_help/blog/tags/vps"},{"label":"VPN\u8f6c\u53d1","permalink":"/UIF_help/blog/tags/vpn\u8f6c\u53d1"}],"readingTime":1.515,"hasTruncateMarker":false,"authors":[{"name":"UIF Office","title":"\u5b98\u65b9","url":"https://github.com/UIforFreedom/UIF","imageURL":"https://avatars.githubusercontent.com/u/140743845?s=48&v=4","key":"uif"}],"frontMatter":{"slug":"locol","title":"\u5185\u7f51\u7a7f\u900f","authors":["uif"],"tags":["\u5185\u7f51\u7a7f\u900f","VPS","VPN\u8f6c\u53d1"]},"nextItem":{"title":"\u8de8\u5883\u7535\u5546\u662f\u5426\u9700\u8981\u6307\u7eb9\u6d4f\u89c8\u5668","permalink":"/UIF_help/blog/browser"}},"content":"---\\n\\n\u6709\u5c5e\u4e8e\u81ea\u5df1\u7684\u4e00\u53f0 VPS \u6709\u4ec0\u4e48\u597d\u5904\uff1f\u5047\u5982\u4f60\u8089\u8eab\u5728\u4e2d\u56fd\u5927\u9646\uff0c\u4f60\u5728\u7f8e\u56fd\u7684\u5bb6\u91cc\u6709\u4e00\u53f0\u5e38\u5e74\u5f00\u673a\u7684\u670d\u52a1\u5668\uff0c\u901a\u5e38\u4e3a\u4e86\u53ef\u4ee5\u50cf\u5728\u7f8e\u56fd\u5bb6\u91cc\u4e00\u6837\u8bbf\u95ee\u7f51\u7edc\u7684\u4efb\u4f55\u8d44\u6e90\uff08\u4e5f\u5c31\u662f\u4fd7\u79f0\u7ffb\u5899\uff09\uff0c\u4f60\u53ef\u4ee5\u901a\u8fc7 VPN \u6280\u672f\uff0c\u628a\u6240\u6709\u7684\u7f51\u7edc\u6d41\u91cf\u8f6c\u53d1\u5230\u7f8e\u56fd\u3002\\n\\n\u540c\u6837\u7684\uff0c\u4f60\u4e5f\u53ef\u4ee5\u5728\u7f8e\u56fd\u65f6\uff0c\u60f3\u8981\u4f7f\u7528\u7f51\u6613\u4e91\u3001QQ\u97f3\u4e50\u7b49\u6709\u7248\u6743\u9694\u79bb\u7684\u5e94\u7528\uff0c\u4e5f\u9700\u8981IP\u201d\u56de\u56fd\u201c\u624d\u80fd\u6b63\u5e38\u4f7f\u7528\u3002\\n\\n## \u4e3a\u4ec0\u4e48\u9700\u8981\u5185\u7f51\u7a7f\u900f\uff1f\\n\\n\u5982\u679c\u4f60\u7684\u9700\u8981\u65f6\u201c\u7ffb\u5899\u201d\u3001\u201c\u56de\u56fd\u201d\uff0c\u901a\u5e38\u53ea\u9700\u8d2d\u4e70\u5177\u6709\u516c\u7f51 IP \u7684 VPS \u5373\u53ef\uff0c\u5e76\u4e0d\u9700\u8981\u5185\u7f51\u7a7f\u900f\u3002\u4f46\u6709\u4e9b\u4eba\u5c31\u559c\u6b22\u6298\u817e\u3002\\n\\n## \u6700\u4f73\u5b9e\u8df5\\n\\n\u5fc5\u8981\u7684\uff1a\\n\\n- \u4e00\u53f0\u5177\u6709\u516c\u7f51\u7684VPS\\n- \u4e24\u53f0\u7535\u8111\u5ba2\u6237\u7aef\uff08Client\uff09\u548c\u670d\u52a1\u7aef\uff08Server\uff09\\n\\n### \u4f7f\u7528 [frp](https://github.com/fatedier/frp)\\n\\n#### \u5c06 frp \u5b89\u88c5\u5728\u516c\u7f51 VPS\\n\\n#### \u5c06 frp \u5b89\u88c5\u5728\u670d\u52a1\u7aef\\n\\n#### \u5728\u670d\u52a1\u7aef\u5b89\u88c5 UIF\\n\\n#### \u5f00\u542f UIF \u5165\u7ad9\\n\\n#### \u5728\u5ba2\u6237\u7aef\u5b89\u88c5 UIF\\n\\n#### \u6dfb\u52a0 UIF \u51fa\u7ad9\\n\\n#### \u5ba2\u6237\u7aef\u542f\u7528 Tun \u6a21\u5f0f\u6216\u8005 HTTP\\n\\n\u542f\u7528 Tun\uff0c\u90a3\u8ddf VPN \u65e0\u5dee\u5f02\uff0c\u4f7f\u7528 HTTP \u5c31\u53ef\u4ee5\u6ee1\u8db3\u7edd\u5927\u90e8\u5206\u4eba\u7fa4\u3002"},{"id":"browser","metadata":{"permalink":"/UIF_help/blog/browser","editUrl":"https://github.com/UIforFreedom/UIF/doc/blog/blog/2024-04-13-browser/index.md","source":"@site/blog/2024-04-13-browser/index.md","title":"\u8de8\u5883\u7535\u5546\u662f\u5426\u9700\u8981\u6307\u7eb9\u6d4f\u89c8\u5668","description":"---","date":"2024-04-13T00:00:00.000Z","formattedDate":"April 13, 2024","tags":[{"label":"\u8de8\u5883","permalink":"/UIF_help/blog/tags/\u8de8\u5883"},{"label":"\u8de8\u5883\u7ffb\u5899","permalink":"/UIF_help/blog/tags/\u8de8\u5883\u7ffb\u5899"},{"label":"\u51fa\u6d77\u6280\u672f","permalink":"/UIF_help/blog/tags/\u51fa\u6d77\u6280\u672f"},{"label":"\u51fa\u6d77\u7ffb\u5899","permalink":"/UIF_help/blog/tags/\u51fa\u6d77\u7ffb\u5899"},{"label":"\u5916\u8d38","permalink":"/UIF_help/blog/tags/\u5916\u8d38"},{"label":"\u4e9a\u9a6c\u900a\u5c01\u53f7","permalink":"/UIF_help/blog/tags/\u4e9a\u9a6c\u900a\u5c01\u53f7"}],"readingTime":6.11,"hasTruncateMarker":false,"authors":[{"name":"UIF Office","title":"\u5b98\u65b9","url":"https://github.com/UIforFreedom/UIF","imageURL":"https://avatars.githubusercontent.com/u/140743845?s=48&v=4","key":"uif"}],"frontMatter":{"slug":"browser","title":"\u8de8\u5883\u7535\u5546\u662f\u5426\u9700\u8981\u6307\u7eb9\u6d4f\u89c8\u5668","authors":["uif"],"tags":["\u8de8\u5883","\u8de8\u5883\u7ffb\u5899","\u51fa\u6d77\u6280\u672f","\u51fa\u6d77\u7ffb\u5899","\u5916\u8d38","\u4e9a\u9a6c\u900a\u5c01\u53f7"]},"prevItem":{"title":"\u5185\u7f51\u7a7f\u900f","permalink":"/UIF_help/blog/locol"},"nextItem":{"title":"\u7ffb\u5899\u5b89\u5168\u5efa\u8bae","permalink":"/UIF_help/blog/safe"}},"content":"---\\n\\n## \u80cc\u666f\u4ecb\u7ecd\\n\\n\u7531\u4e8e\u4e2d\u56fd\u7f51\u7edc\u73af\u5883\u7684\u7279\u6b8a\u6027\uff0c\u4ee5\u53ca\u8f83\u4e3a\u5c01\u95ed\u7684\u7ecf\u6d4e\u5236\u5ea6\uff0c\u5bfc\u81f4\u5916\u8d38\u884c\u4e1a\u9700\u8981\u67d0\u4e9b\u7279\u6b8a\u6280\u672f\u6216\u6280\u5de7\uff0c\u624d\u80fd\u6b63\u5e38\u5de5\u4f5c\u3002\u7279\u522b\u662f\u56fd\u5916\u7535\u5546\u5e73\u53f0\uff0c\u90fd\u6709\u975e\u5e38\u5168\u9762\u7684\u9632\u6b62\u6ee5\u7528\u673a\u5236\u3002\\n\\n\u4f8b\u5982\u8bf4\uff1aMeta \u7cfb\u5217\u4e0b\u7684\u4ea7\u54c1\uff08Facebook \u548c Instagram\uff09\uff0c\u53ea\u8981\u4f60\u7528\u90ae\u7bb1\u6ce8\u518c\u7684\u8d26\u53f7\uff0c\u65e0\u8bba\u4f60\u7684 IP \u6709\u591a\u7eaf\u51c0\uff0c\u65e0\u8bba\u4f60\u7684\u7ffb\u5899\u6280\u672f\u6709\u591a\u4e07\u65e0\u4e00\u5931\uff0c\u65e0\u8bba\u4f60\u6240\u4f7f\u7528\u7684\u6d4f\u89c8\u5668\u662f\u5426\u201c\u552f\u4e00\u201d\uff0c\u90fd\u6709\u975e\u5e38\u9ad8\u7684\u6982\u7387\u4f1a\u5c01\u4f60\u53f7\uff0c\u8981\u6c42\u4f60\u7528\u624b\u673a\u53f7\u9a8c\u8bc1\uff0c\u5e76\u4e14\u4e0a\u4f20\u81ea\u62cd\u7167\u8ba4\u8bc1\u3002\\n\\n## \u672c\u6587\u7ed3\u8bba\\n\\n\u5148\u653e\u672c\u6587\u7ed3\u8bba\uff0c\u65b9\u4fbf\u8bb8\u591a\u4e0d\u60f3\u4ed4\u7ec6\u770b\u7684\u4eba\u3002\\n\\n- \u8de8\u5883\u7535\u5546\u662f\u5426\u9700\u8981\u6307\u7eb9\u6d4f\u89c8\u5668\\n  \u2014\u2014 \u5b8c\u5168\u4e0d\u9700\u8981\\n\\n- \u8de8\u5883\u7535\u5546\u662f\u5426\u9700\u8981\u6d77\u5916 IP\\n  \u2014\u2014 \u5fc5\u987b\u8981\\n\\n- \u8de8\u5883\u7535\u5546\u662f\u5426\u9700\u8981\u7eaf\u51c0 IP\uff08\u539f\u751f IP\uff09\\n  \u2014\u2014 \u6700\u597d\u8981\\n\\n- \u8981\u600e\u4e48\u4fdd\u8bc1\u8fd0\u8425\u8de8\u5883\u7535\u5546\u8d26\u53f7\u5b89\u5168\uff1f\\n  \u2014\u2014 \u4fdd\u6301 IP \u7a33\u5b9a\uff0c\u4e0d\u6ee5\u7528\uff0c\u4e0d\u8fdd\u6cd5\uff0c\u516c\u53f8\u6700\u597d\u6ce8\u518c\u5728\u56fd\u5916\\n\\n## \u8de8\u5883\u7535\u5546\u7b2c\u4e00\u6b65\\n\\n\u80af\u5b9a\u662f\u8981\u89e3\u51b3\u7ffb\u5899\u95ee\u9898\u3002\u8fde\u7f51\u9875\u90fd\u6253\u4e0d\u5f00\uff0c\u8c08\u4f55\u65bd\u5c55\u62f3\u811a\uff1f\u7b2c\u4e00\u4e2a\uff0c\u80af\u5b9a\u4e0d\u8981\u53bb\u4f7f\u7528\u673a\u573a\u3001VPN \u670d\u52a1\u5546\u3002\\n\\n\u6700\u597d\u81ea\u5efa\u4e00\u4e2a\u4e13\u4eab\u7684\u3001\u72ec\u4eab\u7684\uff1b\u6216\u8005\u4f60\u4e5f\u53ef\u4ee5\u7ed9\u94b1\u7ed9\u522b\u4eba\u5e2e\u4f60\u5efa\u597d\u3002\\n\\n### \u7a33\u5b9a\u7684 IP \u662f\u5fc5\u987b\u7684\\n\\n\u5fc5\u987b\u662f\u5f97\u81ea\u5df1\u72ec\u4eab\u3002\u4e8b\u5b9e\u4e0a\uff0c\u81ea\u5efa\u4e00\u4e2a\u72ec\u4eab\u662f\u975e\u5e38\u7b80\u5355\u4e14\u4fbf\u5b9c\u7684\u4e8b\u60c5\uff0c\u4f60\u53ea\u9700\u9009\u62e9\u4e00\u4e2a\u6b63\u786e\u7684 VPS \u5546\u5bb6\uff0c\u6bcf\u4e2a\u6708\u7684\u4ef7\u683c 100 \u4eba\u6c11\u5e01\u5df2\u7ecf\u662f\u9876\u5929\u7684\u5b58\u5728\u3002\\n\\n\u5982\u679c\u88ab\u5c01\u4e86\uff0c\u4f60\u4e5f\u53ef\u4ee5\u4f7f\u7528\u201c\u4e2d\u8f6c\u201d\u7684\u65b9\u5f0f\u4f9d\u7136\u4f7f\u7528\u81ea\u5df1\u7684\u72ec\u4eab IP\u3002\\n\\n### \u6700\u597d\u8981\u7eaf\u51c0\u7684 IP\\n\\n\u76ee\u524d\u5f88\u591a\u5e73\u53f0\u90fd\u4f1a\u53bb\u68c0\u6d4b\u662f\u5426\u662f\u673a\u623f IP\uff08Hosting\uff09\uff0c\u4e5f\u5c31\u662f VPS \u5546\u5bb6\uff0c\u8fd8\u6709\u53e6\u5916\u4e00\u79cd\u662f ISP\uff08\u4f4f\u5b85 IP\uff09\u3002\u8fd8\u662f\u90a3\u53e5\uff0c\u53ea\u8981\u4f60\u9009\u5bf9\u4e86 VPS \u5546\u5bb6\uff0c\u6bcf\u4e2a\u6708 100 \u4eba\u6c11\u5e01\uff0c\u5c31\u53ef\u4ee5\u83b7\u5f97\u4f4f\u5b85 IP\u3002\\n\\n\u4f46\u662f\uff0c\u5e76\u4e0d\u662f\u8bf4\u4f4f\u5b85 IP \u5c31\u662f\u7eaf\u51c0\u7684\uff0c\u8fd8\u662f\u6709\u5f88\u591a\u6ee5\u7528\u7684\u4f4f\u5b85 IP\uff0c\u6bd4\u5982\u8bf4\u201c\u4f4f\u5b85 IP \u4ee3\u7406\u63d0\u4f9b\u5546\u201d\uff0c\u4ed6\u4eec\u63d0\u4f9b\u7684 IP \u5176\u5b9e\u662f\u4e07\u4eba\u9a91\u7684\uff0c\u8868\u9762\u4e0a\u662f\u663e\u793a ISP\uff0c\u5b9e\u9645\u4e0a\u5f88\u591a\u6240\u8c13\u201c\u7f51\u8d5a\u201d\u9879\u76ee\uff0c\u65e9\u5c31\u7528\u70c2\u629b\u5f03\u8fd9\u4e9b IP\uff0c\u7136\u540e\u8f6c\u9500\u7ed9\u4f60\u4e2a\u4eba\u3002\\n\\n### \u6700\u597d\u4f7f\u7528\u5168\u5c40\u6a21\u5f0f\u548c Socks5\\n\\n\u5206\u6d41\u6a21\u5f0f\u53ef\u80fd\u4f1a\u5bfc\u81f4 DNS \u6cc4\u9732\uff0c\u8fd8\u6709\u5f88\u591a\u4ee3\u7406\u8f6f\u4ef6\u6216\u534f\u8bae\u5bf9 UDP \u652f\u6301\u4e0d\u591f\u597d\uff0c\u552f\u4e00\u6709\u660e\u786e\u89c4\u8303\u7684\u4ee3\u7406\u534f\u8bae\u53ea\u6709 Socks5\u3002\\n\\n## \u7b2c\u4e8c\u6b65\\n\\n\u89e3\u51b3\u6536\u6b3e\u95ee\u9898\uff0c\u8fd9\u4e2a\u4e0d\u662f\u7ffb\u5899\u6280\u672f\u95ee\u9898\uff0c\u6211\u5c31\u4e0d\u53d1\u8868\u770b\u6cd5\u3002\u4f46\u662f\u6211\u5f3a\u70c8\u5efa\u8bae\u662f\uff1a\u6ce8\u518c\u5e76\u4f7f\u7528\u6d77\u5916\u516c\u53f8\u6765\u8fd0\u8425\u3002\\n\\n\u80fd\u7701\u7a0e\u4e14\u91d1\u878d\u81ea\u7531\u3002\u76f4\u63a5\u53bb\u6dd8\u5b9d\u3001\u62fc\u591a\u591a\u7b49\u5e73\u53f0\u641c\u201d\u6ce8\u518c\u9999\u6e2f\u516c\u53f8\u201c\uff0c\u9009\u62e9\u9500\u91cf\u6700\u9ad8\u7684\u5373\u53ef\u3002\\n\\n## \u7b2c\u4e09\u6b65\\n\\n\u4f7f\u7528\u82f9\u679c\u624b\u673a\u3001Windows \u7cfb\u7edf\u548c Chrome \u6d4f\u89c8\u5668\u6765\u8fd0\u8425\u3002\u82f9\u679c\u624b\u673a\u662f\u8de8\u5883\u7535\u5546\u5fc5\u5907\u7684\uff0c\u8fd9\u6211\u5c31\u4e0d\u7528\u591a\u8bf4\u4e86\uff0c\u5728 IOS \u4e0a\u5f88\u591a\u4f7f\u7528\u201c\u5c0f\u706b\u7bad\u201d\u6765\u7ffb\u5899\u3002\\n\\n\u8fd9\u91cc\u80af\u5b9a\u662f\u8981\u63a8\u8350\u4e00\u4e0b UIF\uff0c\u53ef\u4ee5\u4f7f\u7528\u5b8c\u5168\u514d\u8d39\u7684 Sing-box\u3002\u4f60\u53ea\u9700\u53bb\u5230 [UIF \u7684\u8bbe\u7f6e](https://uiforfreedom.github.io/#/settings/uif)\uff0c\u70b9\u51fb\u4e00\u4e0b\u201c\u590d\u5236\u5206\u4eab\u94fe\u63a5\u201d\uff0c\u7136\u540e\u628a\u4ed6\u7c98\u8d34\u5230 Sing-box \u8ba2\u9605\u4e2d\uff0c\u5c31\u53ef\u4ee5\u4f7f\u7528\u4e86\u3002\\n\\n## \u7b2c\u56db\u6b65\\n\\n\u8c37\u6b4c\u8d26\u53f7\u9694\u79bb\uff0c\u4e5f\u5c31\u662f\u6240\u8c13\u7684\u201c\u6307\u7eb9\u201d\u3002\u7531\u6d4f\u89c8\u5668\u7684\u7f16\u8bd1\u7248\u672c\u3001\u8bbe\u7f6e\u7684\u8bed\u8a00\u3001\u4ec0\u4e48\u4ec0\u4e48\u6280\u672f\u7279\u5f81\uff0c\u8bf4\u8fd9\u4e2a\u6307\u7eb9\u7eaf\u7cb9\u662f\u201c\u7092\u4f5c\u6982\u5ff5\u201d\u3002\\n\\n\u552f\u4e00\u80fd\u8ffd\u8e2a\u4f60\u8eab\u4efd\u7684\u53ea\u6709 Cookie \u548c\u4f60\u7684 IP\uff1b\u8c37\u6b4c\u516c\u53f8\u66fe\u51e0\u4f55\u65f6\u8fd8\u60f3\u7740\u5f00\u53d1\u4e00\u4e2a\u80fd\u591f\u7528\u4e8e\u5e7f\u544a\u8ffd\u8e2a\u7684\u3001\u6709\u522b\u4e8e Cookie \u7684\u8eab\u4efd\u8bc6\u522b\u7801\uff0c\u906d\u5230\u7a7a\u524d\u53cd\u5bf9\u3002\\n\\n\u6211\u8bf4\u7684\u8fd9\u4e2a\u4f8b\u5b50\u662f\u60f3\u8868\u8fbe\uff0c\u5728\u8f6f\u4ef6\u5f00\u53d1\u65f6\uff0c\u5de5\u7a0b\u5e08\u4eec\u662f\u5f88\u5728\u610f\u8eab\u4efd\u80fd\u5426\u88ab\u8ffd\u8e2a\u7684\u3002\u5728\u7ef4\u62a4 Chrome \u65f6\uff0c\u6839\u672c\u6ca1\u6709\u4eba\u5728\u4e4e\u6240\u8c13\u4ec0\u4e48\u6d4f\u89c8\u5668\u7684\u201c\u6307\u7eb9\u201d\uff0c\u53cd\u5012\u662f\u6709\u201c\u8bbf\u5ba2\u6a21\u5f0f\u201d\u548c\u201c\u591a\u4e2a\u767b\u5f55\u7528\u6237\u201d\uff0c\u8fd9\u4e9b\u90fd\u662f\u53ef\u4ee5\u9694\u79bb Cookie \u548c\u8bbe\u7f6e\u7684\u6a21\u5f0f\u3002\\n\\n\u6240\u4ee5\uff0c\u4f60\u5b8c\u5168\u4e0d\u9700\u8981\u7406\u4f1a\u4ec0\u4e48\u201c\u6307\u7eb9\u201d\u5f71\u54cd\u4f60\u7684\u8fd0\u8425\u3002\u4f60\u9700\u8981\u591a\u4e2a\u8d26\u53f7\u65f6\uff0c\u53ef\u4ee5\u76f4\u63a5\u4f7f\u7528 Chrome \u63d0\u4f9b\u7684\u201c\u591a\u7528\u6237\u201d\u5373\u53ef\u3002\u5f53\u7136\uff0c\u90a3\u79cd\u8981\u7ef4\u62a4\u6210\u5343\u4e0a\u4e07\u4e2a\u8d26\u53f7\u7684\u9664\u5916\uff0c\u4ed6\u4eec\u4e0d\u53ef\u80fd\u4f7f\u7528\u624b\u52a8\u7684\u65b9\u5f0f\u7684\u7ef4\u62a4\u8d26\u53f7\u3002\\n\\n## \u603b\u7ed3\\n\\n\u6211\u8bf4\u7684\u8fd9\u4e9b\u90fd\u662f\u5927\u5b9e\u8bdd\uff0c\u7136\u800c\uff0c\u6211\u5728\u8c37\u6b4c\u4e2d\u641c\u7d22\u201c\u8de8\u5883\u7535\u5546\u662f\u5426\u9700\u8981\u6307\u7eb9\u6d4f\u89c8\u5668\u201d\uff0c\u7b54\u6848\u90fd\u662f\u5fc5\u987b\u8981\u7684\u3002\u5f53\u7136\u4e0d\u662f\u6211\u53cd\u5176\u9053\u800c\u884c\uff0c\u800c\u662f\u628a\u201c\u6b63\u786e\u7b54\u6848\u201d\u63a8\u81f3\u641c\u7d22\u9996\u9875\u7684\u4eba\u5c31\u662f\u201c\u6307\u7eb9\u6d4f\u89c8\u5668\u63d0\u4f9b\u5546\u201d\u3002"},{"id":"safe","metadata":{"permalink":"/UIF_help/blog/safe","editUrl":"https://github.com/UIforFreedom/UIF/doc/blog/blog/2024-02-27-safe/index.md","source":"@site/blog/2024-02-27-safe/index.md","title":"\u7ffb\u5899\u5b89\u5168\u5efa\u8bae","description":"---","date":"2024-02-27T00:00:00.000Z","formattedDate":"February 27, 2024","tags":[{"label":"\u5b89\u5168","permalink":"/UIF_help/blog/tags/\u5b89\u5168"},{"label":"\u7ffb\u5899","permalink":"/UIF_help/blog/tags/\u7ffb\u5899"},{"label":"\u76d1\u63a7","permalink":"/UIF_help/blog/tags/\u76d1\u63a7"}],"readingTime":4.39,"hasTruncateMarker":false,"authors":[{"name":"UIF Office","title":"\u5b98\u65b9","url":"https://github.com/UIforFreedom/UIF","imageURL":"https://avatars.githubusercontent.com/u/140743845?s=48&v=4","key":"uif"}],"frontMatter":{"slug":"safe","title":"\u7ffb\u5899\u5b89\u5168\u5efa\u8bae","authors":["uif"],"tags":["\u5b89\u5168","\u7ffb\u5899","\u76d1\u63a7"]},"prevItem":{"title":"\u8de8\u5883\u7535\u5546\u662f\u5426\u9700\u8981\u6307\u7eb9\u6d4f\u89c8\u5668","permalink":"/UIF_help/blog/browser"},"nextItem":{"title":"\u57fa\u4e8e QUIC \u7684\u4ee3\u7406\u534f\u8bae","permalink":"/UIF_help/blog/quic"}},"content":"---\\n\\n## \u80cc\u666f\u4ecb\u7ecd\\n\\n\u674e\u8001\u5e08\u5728 2024-02-25 \u53d1\u5e03\u4e86\u4e00\u5219[\u7d27\u6025\u901a\u77e5](https://twitter.com/whyyoutouzhele/status/1761709242992427122)\\n\\n> \u201c\u76ee\u524d\u516c\u5b89\u90e8\u6b63\u5728\u6211\u7684160\u4e07\u8ffd\u968f\u8005\u5217\u8868\u548c\u8bc4\u8bba\u533a\u9010\u4e2a\u6392\u67e5\u5173\u6ce8\u6211\u7684\u4eba\uff0c\u4e00\u7ecf\u786e\u8ba4\u8eab\u4efd\u5c31\u4f1a\u901a\u77e5\u5730\u65b9\u8b66\u5bdf\u6253\u7535\u8bdd\u53eb\u4eba\u559d\u8336\u201d\\n\\n\u7167\u6210\u4e86\u4e00\u5b9a\u7a0b\u5ea6\u7684\u6050\u614c\u3002\\n\\n\u672c\u6587\u5217\u51fa\u4e00\u4e9b\u7ffb\u5899\u8f6f\u4ef6\u7684\u5b89\u5168\u5efa\u8bae\uff0c\u4ee5\u4f9b\u8bfb\u8005\u53c2\u8003\u3002\\n\\n\u603b\u7684\u6765\u8bf4\uff0c\u539f\u7406\u5f88\u7b80\u5355\uff1a**\u5c31\u662f\u4e0d\u80fd\u5c06\u56fd\u5185\u201d\u8089\u8eab\u201c\u4e0e\u5899\u5916\u8eab\u4efd\u5173\u8054\u5728\u4e00\u8d77**\\n\\n## \u5207\u52ff\u4f7f\u7528\u56fd\u5185\u624b\u673a\u53f7\u6ce8\u518c\\n\\n\u65e0\u8bba\u662f\u6ce8\u518c\u54ea\u4e2a\u793e\u4ea4\u5a92\u4f53\uff0c\u7528\u56fd\u5185\u624b\u673a\u53f7\u6ce8\u518c\u662f\u7edd\u5bf9\u4e0d\u5b89\u5168\u7684\uff0c\u800c\u4e14\u4e5f\u4e0d\u5e94\u8be5\u4f7f\u7528\u624b\u673a\u53f7\u6ce8\u518c\uff0c\u80fd\u7528\u90ae\u7bb1\u5219\u7528\u90ae\u7bb1\u3002\\n\\n\u90ae\u7bb1\u4f18\u5148\u9009\u62e9 [ProtonMail](https://mail.protonmail.com/)\uff0cGmail \u6ce8\u518c\u8f83\u4e3a\u9ebb\u70e6\u4e14\u53ef\u80fd\u9700\u8981\u9a8c\u8bc1\u624b\u673a\u53f7\u3002\\n\\n## \u5207\u52ff\u5171\u7528\u5bc6\u7801\u548c\u7528\u6237\u540d\\n\\n\u6709\u4e9b\u4eba\u53ef\u80fd\u4f1a\u8d2a\u56fe\u65b9\u4fbf\uff0c\u6240\u6709\u7684\u7f51\u7ad9\u6ce8\u518c\u90fd\u7528\u540c\u4e00\u5957\u7528\u6237\u540d\u548c\u5bc6\u7801\u3002\u6b63\u786e\u7684\u505a\u6cd5\uff1a\u6bcf\u6b21\u6ce8\u518c\u90fd\u7528\u5c3d\u53ef\u80fd\u968f\u673a\u7684\u7528\u6237\u540d\u548c\u5bc6\u7801\u3002\\n\\n## \u80fd\u4f7f\u7528 HTTPS \u5219\u4f7f\u7528 HTTPS\\n\\n\u65e0\u8bba\u4f7f\u7528\u54ea\u4e2a VPN \u670d\u52a1\u5668\u63d0\u4f9b\u5546\u6216\u201c\u673a\u573a\u201d\uff0c**\u4ed6\u4eec\u90fd\u80fd\u51c6\u786e\u65e0\u8bef\u5730\u83b7\u5f97\u4f60\u5c06\u8981\u8bbf\u95ee\u7684\u57df\u540d\u3001IP \u6216\u7aef\u53e3**\u3002\u82e5\u4f60\u4f7f\u7528 HTTPS\uff0c\u90a3\u4e48\u4ed6\u4eec\u5c06\u65e0\u6cd5\u83b7\u5f97\u4f60\u548c\u76ee\u6807\u670d\u52a1\u5668\u4e4b\u95f4\u7684\u901a\u8baf\u5185\u5bb9\uff0c\u4f46\u76ee\u6807\u670d\u52a1\u5668\u662f\u53ef\u4ee5\u88ab\u8bc6\u522b\u51fa\u6765\u7684\u3002\u82e5\u4e0d\u4f7f\u7528 HTTP\uff0c\u90a3\u4e48\u901a\u8baf\u5185\u5bb9\u5c06\u4f1a\u5b8c\u5168\u5730\u66b4\u9732\u3002\\n\\n## \u4f7f\u7528\u56fd\u5916\u52a0\u5bc6 DNS\\n\\n\u5207\u52ff\u4f7f\u7528\u4f20\u7edf\u65e0\u52a0\u5bc6\u7684 `udp://` DNS\uff0c\u4f18\u5148\u4f7f\u7528 `https://`\u3001`tls://`\u7684\u52a0\u5bc6 DNS\u3002\u800c\u4e14\u662f\u975e\u4e2d\u56fd\u5927\u9646\u653f\u5e9c\u63a7\u5236\u7684 DNS \u63d0\u4f9b\u5546\uff0c\u4f8b\u5982\uff1a\\n\\n- `https://dns.google/dns-query`\\n- `https://1.1.1.1/dns-query`\\n\\n\u4f60\u53ef\u4ee5\u5728 [UIF \u8def\u7531](https://uiforfreedom.github.io/#/route/my) \u4fee\u6539\u4f60\u5f53\u524d\u6240\u4f7f\u7528\u7684 DNS \u5730\u5740\\n\\n## \u4e0d\u7528\u5206\u6d41\\n\\n\u4e0d\u4f7f\u7528 `\u56fd\u5185\u76f4\u8fde\uff0c\u56fd\u5185\u4ee3\u7406` \u5206\u6d41\u529f\u80fd\uff0cClash \u4e2d\u79f0\u4e3a\u201c\u89c4\u5219\u201d\uff0c\u82e5\u5c06\u8bbf\u95ee\u670d\u52a1\u5668\u4e2d\u63d2\u5165\u4e86\u540e\u7f00\u4e3a.cn \u7684\u7f51\u5740\uff0c`UIF` \u4f1a\u5c06\u5176\u8bc6\u522b\u56fd\u5185\u5730\u5740\uff0c\u6240\u4ee5\u4f1a\u5bfc\u81f4\u88ab\u8bc6\u522b\u51fa\u4f7f\u7528\u4e86\u4e0d\u540c\u7684 IP\u3002\\n\\n\u5efa\u8bae\u4f7f\u7528 `\u5168\u90e8\u4ee3\u7406`\u3002\\n\\n\u4f60\u53ef\u4ee5\u5728 [UIF \u8def\u7531](https://uiforfreedom.github.io/#/route/my) \u4fee\u6539\u4f60\u5f53\u524d\u6240\u4f7f\u7528\u7684\u8def\u7531\u89c4\u5219\u3002\\n\\n## \u81ea\u5efa\u201c\u7ffb\u5899\u201d\u670d\u52a1\u5668\u65f6\uff0c\u53ea\u9009\u201c\u5927\u5382\u201d\\n\\n\u81ea\u5efa\u201d\u7ffb\u5899\u201c\u670d\u52a1\u5668\uff0c\u9700\u8981\u8d2d\u4e70 VPS\uff0c\u5e02\u9762\u4e0a VPS \u7684\u7ade\u4e89\u5f88\u6fc0\u70c8\uff0c\u6709\u8bb8\u8bb8\u591a\u591a\u7684\u53ef\u4ee5\u9009\u62e9\u7684\u5382\u724c\u3002\u5efa\u8bae\u53ea\u4f7f\u7528\u201d\u5927\u5382\u201c\uff1a\\n\\n- \u8c37\u6b4c\u4e91\\n- \u4e9a\u9a6c\u900a\u4e91\\n- \u7532\u9aa8\u6587\u4e91\\n\\n\u5207\u52ff\u4f7f\u7528\u201c\u4e0d\u77e5\u540d\u201d\u3001\u5bb9\u6613\u53d7\u5230\u5a01\u80c1\u7684\u201c\u5c0f\u5382\u201d\uff0c\u4ed6\u4eec\u5f80\u5f80\u4f1a\u5f88\u613f\u610f\u914d\u5408\u8c03\u67e5\u3002\\n\\n## \u81ea\u5efa\u201c\u7ffb\u5899\u201d\u670d\u52a1\u5668\u65f6\uff0c\u52a1\u5fc5\u4f7f\u7528 TLS\\n\\n\u65e0\u8bba\u662f\u54ea\u79cd\u4ee3\u7406\u534f\u8bae\uff0c\u53ea\u8981\u4f60\u5957\u4e0a\u4e86 TLS\uff0c\u5c31\u53ef\u4ee5\u514d\u906d\u76d1\u63a7\u3001\u7834\u89e3\u3002\u800c\u4e14\u5f88\u91cd\u8981\u7684\u4e00\u70b9\uff0c\u4e0d\u5e94\u8be5\u4f7f\u7528 `Skip-Verify\uff08insecure\uff09`\u3001`\u4fe1\u4efb\u7cfb\u7edf\u9ed8\u8ba4\u6839\u8bc1\u4e66`\uff1b\u6700\u4fdd\u9669\u65b9\u6cd5\uff1a`\u81ea\u7b7e\u8bc1\u4e66`\\n\\n[UIF \u7684 TLS \u914d\u7f6e](https://uiforfreedom.github.io/#/in/my) \u9ed8\u8ba4\u4f7f\u7528`\u81ea\u7b7e\u8bc1\u4e66`\u65b9\u5f0f\uff0c\u6bcf\u4e2a\u7528\u6237\u90fd\u4f1a\u6709\u81ea\u5df1\u7684 `\u8bc1\u4e66` \u548c `\u79d8\u94a5`\u3002\\n\\n## \u7559\u8a00\u3001\u8bc4\u8bba\u65f6\u6ce8\u610f\u201c\u793e\u5de5\u201d\u653b\u51fb\\n\\n\u53d1\u5e03\u7167\u7247\u3001\u5e16\u5b50\u3001\u8bc4\u8bba\u7b49\uff0c\u5f80\u5f80\u4f1a\u5728\u4e0d\u7ecf\u610f\u95f4\u6cc4\u9732\u4f60\u7684\u4e2a\u4eba\u4fe1\u606f\u3002\u5c3d\u53ef\u80fd\u505a\u5230\u201c\u6c89\u9ed8\u662f\u91d1\u201d\u3002\\n\\n\x3c!-- ## \u6700\u540e\uff0c\u4f55\u4e3a\u8a00\u8bba\u81ea\u7531\uff1f --\x3e\\n\\n\x3c!-- \u8a00\u8bba\u81ea\u7531\u662f\u6307\uff0c\u65e0\u8bba\u516c\u6c11\u5982\u4f55\u6279\u8bc4\u3001\u6c61\u8511\u3001\u9020\u8c23\u653f\u5e9c\uff08\u5305\u62ec\u6c11\u9009\u5b98\u5458\u548c\u7531\u7eb3\u7a0e\u4eba\u4f9b\u517b\u7684\u516c\u52a1\u5458\uff09\uff0c\u90fd\u4e0d\u4f1a\u53d7\u5230\u6765\u81ea\u653f\u5e9c\u7684\u5ba1\u67e5\u3001\u6253\u538b\u3001\u5904\u7f5a\u3002 --\x3e"},{"id":"quic","metadata":{"permalink":"/UIF_help/blog/quic","editUrl":"https://github.com/UIforFreedom/UIF/doc/blog/blog/2023-09-14-quic/index.md","source":"@site/blog/2023-09-14-quic/index.md","title":"\u57fa\u4e8e QUIC \u7684\u4ee3\u7406\u534f\u8bae","description":"---","date":"2023-09-14T00:00:00.000Z","formattedDate":"September 14, 2023","tags":[{"label":"\u4ee3\u7406\u6280\u672f","permalink":"/UIF_help/blog/tags/\u4ee3\u7406\u6280\u672f"},{"label":"UDP","permalink":"/UIF_help/blog/tags/udp"},{"label":"\u52a0\u5bc6","permalink":"/UIF_help/blog/tags/\u52a0\u5bc6"}],"readingTime":5.945,"hasTruncateMarker":false,"authors":[{"name":"UIF Office","title":"\u5b98\u65b9","url":"https://github.com/UIforFreedom/UIF","imageURL":"https://avatars.githubusercontent.com/u/140743845?s=48&v=4","key":"uif"}],"frontMatter":{"slug":"quic","title":"\u57fa\u4e8e QUIC \u7684\u4ee3\u7406\u534f\u8bae","authors":["uif"],"tags":["\u4ee3\u7406\u6280\u672f","UDP","\u52a0\u5bc6"]},"prevItem":{"title":"\u7ffb\u5899\u5b89\u5168\u5efa\u8bae","permalink":"/UIF_help/blog/safe"},"nextItem":{"title":"Welcome","permalink":"/UIF_help/blog/welcome"}},"content":"---\\n\\n## QUIC \u7b80\u4ecb\\n\\nQUIC \u662f\u57fa\u4e8e UDP \u7684\u4f20\u8f93\u5c42\u534f\u8bae\uff0c\u51cf\u5c11\u4e86\u5efa\u7acb\u94fe\u63a5\u6240\u9700\u7684 RTT\uff0c\u89e3\u51b3\u4e86\u591a\u8def\u590d\u7528\u6240\u5e26\u6765\u7684\u95ee\u9898\u3002\u57fa\u4e8e QUIC \u7684 HTTP \u5df2\u7ecf\u88ab\u6807\u51c6\u59d4\u5458\u4f1a\u63a5\u6536\u6210\u4e3a `HTTP3`\u3002\\n\\n**\u5728\u53ef\u9884\u89c1\u7684\u672a\u6765\uff0cHTTP3 \u5c06\u4f1a\u88ab\u5e7f\u6cdb\u4f7f\u7528\u3002**\u76ee\u524d\uff0c\u8c37\u6b4c\u5168\u7cfb\u4ea7\u54c1\u5df2\u652f\u6301 QUIC\u3002\\n\\n## \u591a\u8def\u590d\u7528\u6240\u5e26\u6765\u7684\u95ee\u9898\\n\\n`HTTP2`\u662f\u57fa\u4e8e TCP \u590d\u7528\u7684\uff0c\u867d\u7136\u53ef\u4ee5\u51cf\u5c11\u5efa\u7acb\u94fe\u63a5\u7684\u5ef6\u8fdf\uff0c\u4f46\u662f\u4f20\u8f93\u6548\u7387\u4e0d\u9ad8\uff0c\u4e3b\u8981\u7684\u539f\u56e0\u662f`\u961f\u5934\u963b\u585e`\uff0c\u4e5f\u5c31\u662f A \u5fc5\u987b\u8981\u5148\u4e8e B\uff0c\u5982\u679c\u5373\u4f7f B \u5148\u5230\u8fbe\u4e86\u76ee\u6807\u7f51\u7edc\uff0cA \u4e22\u5931\u4e86\u9700\u8981\u91cd\u4f20\uff0cB \u4e5f\u5fc5\u987b\u8981\u7b49\u5f85 A\uff0c\u5373\u4f7f B \u5df2\u7ecf\u6210\u529f\u88ab\u63a5\u6536\u4e86\u3002\\n\\n`\u961f\u5934\u963b\u585e` \u4e0d\u5355\u5355\u662f TCP \u7684\u539f\u56e0\uff0c\u4e5f\u6709 TLS \u7684\u539f\u56e0\u3002\u56e0\u4e3a TLS \u4e5f\u6709\u4fdd\u8bc1\u6b63\u786e\u63a5\u6536\u987a\u5e8f\u7684\u529f\u80fd\u3002\u6240\u4ee5\uff0c\u60f3\u8981\u5f7b\u5e95\u89e3\u51b3\u8fd9\u4e2a\u95ee\u9898\uff0cQUIC \u5fc5\u987b\u8981\u7ed3\u5408 TLS\u3002\\n\\n## \u57fa\u4e8e UDP \u7684 QUIC\\n\\n\u57fa\u4e8e UDP \u662f\u5fc5\u7136\u7684\u9009\u62e9\uff0c\u56e0\u4e3a\u6211\u4eec\u4e0d\u53ef\u80fd\u7f51\u7edc\u5c42\u91cd\u65b0\u8bbe\u8ba1\u4e00\u4e2a\u4f20\u8f93\u5c42\u534f\u8bae\uff0c\u8fd9\u6837\u505a\u7684\u6210\u672c\u662f\u5de8\u5927\u7684\uff1b\u53c2\u8003 IPv6\uff0c\u4e0d\u517c\u7528\u5e26\u6765\u7684\u6210\u672c\u4f7f\u5f97\u8bbe\u5907\u4ea7\u5546\u548c\u4f7f\u7528\u4e0d\u79ef\u6781\u63a8\u5e7f\u66f4\u52a0\u5148\u8fdb\u7684\u534f\u8bae\u3002\\n\\n\u53ef\u80fd\u6709\u4eba\u4f1a\u7591\u8651\uff1a\\n\\n> UDP \u4f1a\u88ab\u8fd0\u8425\u5546 QOS\uff0c\u4fd7\u79f0\u9650\u901f\u3002\u8fd9\u6837\u4f1a\u5bfc\u81f4 QUIC \u7684\u5e26\u5bbd\u6027\u80fd\u4e0d\u4f73\u3002\\n\\n\u6211\u4eec\u8ba4\u4e3a UDP \u4f20\u8f93\u8d28\u91cf\u4e0d\u4f73\uff0c\u5927\u6982\u7387\u662f\u56e0\u4e3a\u8fd0\u8425\u5546\u5bf9 UDP NAT \u652f\u6301\u4e0d\u4f73\u5bfc\u81f4\u7684\u3002\u4f7f\u7528 UDP \u5e76\u4e0d\u80fd\u7a81\u7834\u8fd0\u8425\u5546\u5bf9\u7f51\u7edc\u5e26\u5bbd\u7684\u9650\u5236\u3002\\n\\n\u53c2\u8003\u8fd9\u7bc7\u6587\u7ae0 [#776](https://github.com/xtaci/kcptun/issues/776)\uff0c\u5176\u4e2d\u63d0\u5230\uff1a\\n\\n> \u8fd9\u79cd\u73b0\u8c61\u5f88\u660e\u663e\uff0c\u6bd4\u5982\u4f60\u521a\u5f00\u59cb\u6d4b\u8bd5 kcptun \u5f00\u542f\u7684\u4e00\u6bb5\u65f6\u95f4\uff0c\u901f\u5ea6\u662f\u633a\u5feb\uff0c\u4f46\u662f\u6302\u4e45\u4e86\uff0c\u5c31\u53d8\u5f97\u975e\u5e38\u6162\uff0c\u8fd9\u65f6\u5019\uff0c\u53ea\u9700\u8981\u91ca\u653e\u6389\u96a7\u9053\uff0c\u91cd\u65b0\u53d1\u8d77\u65b0\u96a7\u9053\u5373\u53ef\\n\\n\u56e0\u4e3a NAT \u7684\u539f\u56e0\uff0cQUIC \u4e5f\u6709\u5fc3\u8df3\u5305\u7684\u8bbe\u8ba1\uff0c\u7528\u4e8e\u7ef4\u62a4 UDP session\uff0c\u4fdd\u6301\u8def\u7531\u5668\u80fd\u591f\u6b63\u786e\u5730\u8f6c\u53d1\u3002\u4f46\u662f\u6709\u4e9b\u8def\u7531\u5668\u53ef\u80fd\u56fe\u7701\u4e8b\uff0c\u4e00\u5b9a\u65f6\u95f4\u540e\u65e0\u8bba\u662f\u5426\u6d3b\u8dc3\u90fd\u4f1a\u76f4\u63a5\u5173\u95ed\uff1b\u8fd9\u6837\u4e00\u6765\uff0c\u5373\u8282\u7701\u4e86\u5e26\u5bbd\u5185\u5b58\uff0c\u53c8\u4e0d\u8fdd\u53cd UDP \u534f\u8bae\u3002\\n\\n\u4e00\u65e6\u968f\u7740 HTTP3 \u7684\u5e7f\u6cdb\u5e94\u7528\uff0c\u5728\u6fc0\u70c8\u7684\u7ade\u4e89\u73af\u5883\u4e0b\uff0c\u6240\u8c13\u6709 QOS \u7684\u8fd0\u8425\u5546\u4f1a\u88ab\u6d88\u8d39\u8005\u6dd8\u6c70\u3002\\n\\n## QUIC \u7684\u591a\u8def\u590d\u7528\\n\\nQUIC \u5728\u7528\u6237\u5c42 `\u7ba1\u7406\u94fe\u63a5\uff08Connection\uff09` \u548c\u5b9e\u73b0`\u62e5\u585e\u63a7\u5236`\u3002\u5e76\u4e14\u4f7f\u7528 Connection ID \u6765\u6807\u8bb0\u6bcf\u4e00\u6761\u94fe\u63a5\uff0c\u4e0d\u518d\u4f7f\u7528\u4f20\u7edf\u7684 IP \u56db\u5143\u7ec4\uff0c\u4e5f\u5c31\u662f\u8bf4 QUIC \u7684\u94fe\u63a5\u662f IP \u65e0\u5173\u7684\u3002\\n\\n\u65e0\u8bba\u5ba2\u6237\u7aef\u8d70\u5230\u54ea\u91cc\uff0c\u53ea\u8981\u6709 Connection ID\uff0c\u5c31\u53ef\u4ee5\u88ab\u670d\u52a1\u7aef\u8bc6\u522b\u5230\u3002\u5728\u79fb\u52a8\u7684\u7f51\u7edc\u73af\u5883\u4e2d\uff0c\u8fd9\u6837\u505a\u6709\u5de8\u5927\u597d\u5904\uff0c\u4f8b\u5982\u4e58\u5750\u6c7d\u8f66\u3001\u9ad8\u94c1\u7b49\u4ea4\u901a\u5de5\u5177\u65f6\uff0c\u5373\u4f7f\u4e0d\u65ad\u66f4\u6362\u7f51\u7edc\uff08IP\uff09\uff0c\u4e5f\u65e0\u9700\u91cd\u65b0\u4e0e\u670d\u52a1\u5668\u5efa\u7acb\u94fe\u63a5\u540e\u518d\u4f20\u8f93\u6570\u636e\u3002\\n\\n## \u4e0e TLS \u5b89\u5168\u534f\u8bae\u9ad8\u5ea6\u96c6\u6210\\n\\nQUIC \u662f\u5f3a\u5236\u4f7f\u7528 TLS \u7684\u3002\\n\\n\u4e0a\u6587\u63d0\u5230\uff0cTLS \u4e5f\u6709`\u961f\u5934\u963b\u585e`\u7684\u95ee\u9898\u3002\u4e3a\u4e86\u89e3\u51b3\u8fd9\u4e2a\u95ee\u9898\uff0cQUIC \u4fee\u6539\u4e86 TLS \u534f\u8bae\uff0c\u4ec5\u4f7f\u7528\u7531 TLS \u534f\u5546\u51fa\u7684\u79d8\u94a5\uff0c\u7531 QUIC \u6765\u4fdd\u8bc1\u4f20\u8f93\u987a\u5e8f\u6b63\u786e\uff0c\u4e5f\u5c31\u662f TLS \u4ec5\u5728\u63e1\u624b\u9636\u6bb5\u88ab\u4f7f\u7528\u5230\u3002\\n\\n## \u4ee3\u7406\u534f\u8bae\\n\\n\u50cf HTTP \u548c Sock5 \u7b49\u57fa\u4e8e\u4f20\u8f93\u5c42\u7684\u4ee3\u7406\u534f\u8bae\uff0c\u6839\u636e\u7f51\u7edc\u534f\u8bae\u7684\u5236\u5b9a\u539f\u5219\uff0c\u4ed6\u4eec\u662f\u4e0d\u4f1a\u89c4\u5b9a\u4f20\u8f93\u7684\u5177\u4f53\u5185\u5bb9\u7684\uff0c\u4e5f\u5c31\u662f\u8bf4\u53ef\u4ee5\u6839\u636e\u7528\u6237\u7684\u610f\u613f\u81ea\u7531\u66ff\u6362\u4f7f\u7528\u4f20\u8f93\u5c42\u3002\\n\\n\u4e00\u4e2a\u8f83\u65e9\u5b9e\u73b0\u57fa\u4e8e QUIC \u7684\u4ee3\u7406\u5de5\u5177\u6709 [v2ray](https://github.com/v2fly/v2ray-core)\uff0c\u4ed6\u53ef\u642d\u914d\u5404\u79cd\u4f20\u8f93\u5c42+\u4ee3\u7406\u5c42\u7684\u7ec4\u5408\u3002\\n\\n## UDP \u7684\u4f20\u8f93\\n\\n\u9700\u8981\u4f20\u8f93 UDP \u6570\u636e\u7684\u573a\u666f\uff0c\u4e00\u822c\u90fd\u662f VPN \u6240\u9700\u8981\u7684\u3002\u4ed6\u4eec\u4f1a\u622a\u83b7\u64cd\u4f5c\u7cfb\u7edf\u7684\u6240\u6709\u6d41\u91cf\uff08\u5305\u62ec DNS\uff09\uff0c\u7136\u540e\u4f20\u8f93\u5230\u4ee3\u7406\u670d\u52a1\u5668\u3002\\n\\n\u5728\u6b64\u4e4b\u524d\uff0c\u6211\u4eec\u4e00\u822c\u628a UDP \u6570\u636e\u653e\u5728\u4f20\u8f93\u5c42\u4e2d\uff0c\u4e5f\u5c31\u662f UDP over TCP\u3002 \u5728 QUIC \u4e2d\u4e5f\u662f\u53ef\u4ee5\u5927\u540c\u5c0f\u5f02\uff0cUDP over QUIC\u3002\\n\\n\u4f46\u662f\u6709\u4e00\u4e2a\u95ee\u9898\uff0c\u5047\u5982\u8fd9\u4e2a UDP \u662f QUIC\uff0c\u5373 QUIC over QUIC\uff0c\u4f20\u8f93\u5c42\u518d\u52a0\u4e0a\u4e00\u4e2a\u4f20\u8f93\u5c42\uff0c\u8fd9\u53c8\u4f1a\u9020\u6210\u672c\u6765\u6211\u4eec\u8981\u89e3\u51b3\u7684 `\u961f\u5934\u963b\u585e`\u3002\u56e0\u6b64\uff0c\u5728\u4ee3\u7406\u793e\u533a\u4e2d\uff0c\u4e00\u822c\u5efa\u8bae\u7528\u6237\u7981\u7528 443 UDP \u7aef\u53e3\uff0c\u6765\u89c4\u907f\u8fd9\u4e2a\u95ee\u9898\u3002\\n\\n## \u7ec8\u6781\u89e3\u51b3\u65b9\u6848\\n\\nQUIC \u8fd8\u8bbe\u8ba1\u4e86 UDP \u4f20\u8f93\u6a21\u5f0f\uff0c\u4e5f\u5c31\u662f\u8bf4\u4f7f\u7528\u8be5\u6a21\u5f0f\u4f20\u8f93\u7684\u6570\u636e\uff0c\u5c06\u4e0e\u6b63\u5e38 UDP \u4f20\u8f93\u6570\u636e\u65e0\u5f02\uff08\u52a0\u5bc6\u9664\u5916\uff09\u3002\u4ece\u7406\u8bba\u4e0a\u6765\u8bf4\uff0cUDP over UDP \u5c31\u662f\u7ec8\u6781\u89e3\u51b3\u65b9\u6848\u3002\\n\\n\u6bd4\u5982\u8bf4 [TUIC](https://github.com/EAimTY/tuic) \u5c31\u662f\u57fa\u4e8e QUIC \u7684\u4ee3\u7406\u534f\u8bae\u3002\u62e5\u6709 QUIC \u7684\u4f18\u70b9\uff1a\u8d85\u4f4e\u7684\u5ef6\u8fdf\u3001\u5b8c\u5168\u7684\u591a\u8def\u590d\u7528\u3001UDP \u4ee3\u7406\uff08\u76ee\u524d\u5df2\u88ab\u5220\u5e93\uff0c\u8bf7\u4f7f\u7528 Hysteria2 \u4ee3\u66ff\uff09\u3002\\n\\n---\\n\\nUIF \u652f\u6301\u4f7f\u7528 [Hysteria2](https://github.com/EAimTY/tuic)\uff0c\u6b22\u8fce\u5927\u5bb6\u4f7f\u7528\u3002"},{"id":"welcome","metadata":{"permalink":"/UIF_help/blog/welcome","editUrl":"https://github.com/UIforFreedom/UIF/doc/blog/blog/2023-08-03-welcome/index.md","source":"@site/blog/2023-08-03-welcome/index.md","title":"Welcome","description":"---","date":"2023-08-03T00:00:00.000Z","formattedDate":"August 3, 2023","tags":[{"label":"\u9996\u6b21\u4eae\u76f8","permalink":"/UIF_help/blog/tags/\u9996\u6b21\u4eae\u76f8"},{"label":"\u7ffb\u5899","permalink":"/UIF_help/blog/tags/\u7ffb\u5899"},{"label":"VPN","permalink":"/UIF_help/blog/tags/vpn"},{"label":"\u7b80\u6613","permalink":"/UIF_help/blog/tags/\u7b80\u6613"},{"label":"\u7f8e\u89c2","permalink":"/UIF_help/blog/tags/\u7f8e\u89c2"}],"readingTime":0.205,"hasTruncateMarker":false,"authors":[{"name":"UIF Office","title":"\u5b98\u65b9","url":"https://github.com/UIforFreedom/UIF","imageURL":"https://avatars.githubusercontent.com/u/140743845?s=48&v=4","key":"uif"}],"frontMatter":{"slug":"welcome","title":"Welcome","authors":["uif"],"tags":["\u9996\u6b21\u4eae\u76f8","\u7ffb\u5899","VPN","\u7b80\u6613","\u7f8e\u89c2"]},"prevItem":{"title":"\u57fa\u4e8e QUIC \u7684\u4ee3\u7406\u534f\u8bae","permalink":"/UIF_help/blog/quic"}},"content":"---\\n\\n\u4f60\u53ef\u4ee5\u76f4\u63a5\u6253\u5f00 [uiforfreedom.github.io](https://uiforfreedom.github.io/) \u6d4f\u89c8 UIF \u7684\u5168\u90e8\u529f\u80fd\uff0c\u4f46\u60f3\u8981\u5728\u672c\u5730\u4f7f\u7528\uff0cUIF \u540e\u7aef\u662f\u5fc5\u987b\u7684\u3002\\n\\n\u67e5\u770b [\u5feb\u901f\u4f7f\u7528\u6559\u7a0b](https://uiforfreedom.github.io/UIF_help/docs/quic/intro)"}]}')}}]);